namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public required string Code { get; set; }
    public required string Title { get; set; }
    public required string Description { get; set; }
    public int Credits { get; set; }
    public required string Schedule { get; set; }
    public required string InstructorName { get; set; }
    public required string InstructorBio { get; set; }
    public required string DepartmentCode { get; set; }
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public required string Code { get; set; }
    public required string Name { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9\-]+$", ErrorMessage = "Student ID must contain only letters, numbers, and hyphens.")]
    [StringLength(20)]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CourseCatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Code = "CS", Name = "Computer Science" },
        new() { Code = "MATH", Name = "Mathematics" },
        new() { Code = "ENG", Name = "English" },
        new() { Code = "PHYS", Name = "Physics" },
        new() { Code = "HIST", Name = "History" },
    ];

    private readonly List<Course> _courses =
    [
        new()
        {
            Id = 1, Code = "CS 101", Title = "Introduction to Computer Science",
            Description = "A broad introduction to computer science covering computational thinking, basic programming in Python, data representation, and an overview of how computers work. No prior experience required.",
            Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentCode = "CS",
            InstructorName = "Dr. Ada Lovelace", InstructorBio = "Dr. Lovelace holds a Ph.D. in Computer Science from MIT and has over 15 years of teaching experience. Her research focuses on programming language design and CS education.",
            IsFeatured = true
        },
        new()
        {
            Id = 2, Code = "CS 201", Title = "Data Structures and Algorithms",
            Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques (sorting, searching, dynamic programming). Includes weekly programming assignments.",
            Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentCode = "CS",
            InstructorName = "Dr. Alan Turing", InstructorBio = "Dr. Turing is a professor of computer science specializing in algorithm analysis and computational complexity. He has published over 40 papers in top-tier journals.",
            IsFeatured = true
        },
        new()
        {
            Id = 3, Code = "CS 310", Title = "Database Systems",
            Description = "Principles of database design, relational algebra, SQL, transaction processing, and an introduction to NoSQL databases. Students complete a semester-long project building a full database application.",
            Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentCode = "CS",
            InstructorName = "Dr. Edgar Codd", InstructorBio = "Dr. Codd is an associate professor who spent 10 years in industry building large-scale data systems before joining academia. He teaches courses in databases and distributed systems.",
            IsFeatured = false
        },
        new()
        {
            Id = 4, Code = "MATH 101", Title = "Calculus I",
            Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering. Emphasis on conceptual understanding and problem solving.",
            Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentCode = "MATH",
            InstructorName = "Dr. Emmy Noether", InstructorBio = "Dr. Noether is a distinguished professor of mathematics with expertise in abstract algebra and mathematical physics. She has received multiple teaching excellence awards.",
            IsFeatured = true
        },
        new()
        {
            Id = 5, Code = "MATH 201", Title = "Linear Algebra",
            Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and inner product spaces. Applications to computer graphics, data science, and engineering.",
            Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentCode = "MATH",
            InstructorName = "Dr. Srinivasa Ramanujan", InstructorBio = "Dr. Ramanujan is an assistant professor whose research spans number theory and matrix analysis. He is known for his engaging lecture style and creative problem sets.",
            IsFeatured = false
        },
        new()
        {
            Id = 6, Code = "ENG 101", Title = "College Composition",
            Description = "Develops skills in academic writing, critical reading, and argumentation. Students write multiple essays progressing from personal narrative to research-based argument.",
            Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentCode = "ENG",
            InstructorName = "Prof. Virginia Woolf", InstructorBio = "Prof. Woolf is a senior lecturer in English with a focus on modern literature and composition pedagogy. She has mentored hundreds of first-year students in academic writing.",
            IsFeatured = false
        },
        new()
        {
            Id = 7, Code = "ENG 220", Title = "American Literature",
            Description = "Survey of American literature from the colonial period to the present. Readings include works by Hawthorne, Twain, Fitzgerald, Morrison, and contemporary authors.",
            Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", DepartmentCode = "ENG",
            InstructorName = "Dr. Ralph Ellison", InstructorBio = "Dr. Ellison is a professor of English and American Studies. His research explores themes of identity and race in 20th-century American fiction.",
            IsFeatured = true
        },
        new()
        {
            Id = 8, Code = "PHYS 101", Title = "General Physics I",
            Description = "Mechanics, thermodynamics, and waves. Includes a weekly lab section with hands-on experiments. Calculus-based; co-requisite of MATH 101 or equivalent.",
            Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:00 PM", DepartmentCode = "PHYS",
            InstructorName = "Dr. Marie Curie", InstructorBio = "Dr. Curie is a research professor with extensive experience in experimental physics. She emphasizes hands-on learning and real-world applications in her courses.",
            IsFeatured = false
        },
        new()
        {
            Id = 9, Code = "PHYS 250", Title = "Modern Physics",
            Description = "Introduction to special relativity, quantum mechanics, atomic structure, and nuclear physics. Explores the experiments and reasoning that revolutionized our understanding of nature.",
            Credits = 3, Schedule = "Tue/Thu 10:00–11:20 AM", DepartmentCode = "PHYS",
            InstructorName = "Dr. Richard Feynman", InstructorBio = "Dr. Feynman is a celebrated physics professor known for his ability to make complex topics accessible. He has authored several popular science books alongside his academic publications.",
            IsFeatured = true
        },
        new()
        {
            Id = 10, Code = "HIST 101", Title = "World History to 1500",
            Description = "Survey of world civilizations from prehistory through the Renaissance. Covers the rise and fall of empires, cultural exchange, and the development of major world religions.",
            Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", DepartmentCode = "HIST",
            InstructorName = "Dr. Herodotus Smith", InstructorBio = "Dr. Smith is an associate professor of history specializing in ancient civilizations and historiography. He brings archaeological fieldwork experience into the classroom.",
            IsFeatured = false
        },
        new()
        {
            Id = 11, Code = "HIST 205", Title = "The Modern World",
            Description = "Examines global history from the Enlightenment to the present, including industrialization, colonialism, world wars, decolonization, and globalization.",
            Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentCode = "HIST",
            InstructorName = "Dr. Mary Beard", InstructorBio = "Dr. Beard is a professor of modern history and a public intellectual who frequently writes for mainstream media. Her courses are known for lively debate and primary source analysis.",
            IsFeatured = false
        },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string code) =>
        _departments.FirstOrDefault(d => d.Code.Equals(code, StringComparison.OrdinalIgnoreCase));

    public List<Course> GetCourses(string? department = null, string? search = null)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(department))
            query = query.Where(c => c.DepartmentCode.Equals(department, StringComparison.OrdinalIgnoreCase));

        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(c =>
                c.Title.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(search, StringComparison.OrdinalIgnoreCase));

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
}

