@page "/courses"
@using UniversityCourseCatalog.Services
@inject CourseCatalogService CatalogService

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

@{
    var departments = CatalogService.GetDepartments();
    var courses = CatalogService.GetCourses(Department, Search);
    var currentDeptName = string.IsNullOrWhiteSpace(Department)
        ? null
        : CatalogService.GetDepartment(Department)?.Name;
}

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-4">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="search" value="@Search"
               placeholder="Course title, code, or instructor" />
    </div>
    <div class="col-md-4">
        <label for="department" class="form-label">Department</label>
        <select class="form-select" id="department" name="department">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Code" selected="@(dept.Code == Department)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button type="submit" class="btn btn-primary me-2">Filter</button>
        <a href="courses" class="btn btn-outline-secondary">Clear</a>
    </div>
</form>

@if (currentDeptName is not null)
{
    <h5 class="mb-3">Showing courses in <strong>@currentDeptName</strong></h5>
}

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@course.DepartmentCode</td>
                        <td>@course.Credits</td>
                        <td>@course.Schedule</td>
                        <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery]
    public string? Department { get; set; }

    [SupplyParameterFromQuery]
    public string? Search { get; set; }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CourseCatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Submit Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course. You will receive confirmation from the registrar's office.</p>

@if (Submitted)
{
    var selectedCourse = CatalogService.GetCourse(Model.CourseId);

    <div class="alert alert-success" role="alert">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.FullName</strong> (ID: @Model.StudentId). Your enrollment request for
            <strong>@selectedCourse?.Code – @selectedCourse?.Title</strong> has been received.</p>
        <hr />
        <p class="mb-0">The registrar's office will review your request and send a confirmation to your university email.</p>
    </div>
    <a href="enroll" class="btn btn-primary">Submit Another Request</a>
}
else
{
    var courses = CatalogService.GetCourses();

    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" class="mt-4">
        <DataAnnotationsValidator />
        <AntiforgeryToken />

        <div class="row">
            <div class="col-md-6 mb-3">
                <label for="fullName" class="form-label">Full Name</label>
                <InputText id="fullName" class="form-control" @bind-Value="Model.FullName" />
                <ValidationMessage For="() => Model.FullName" />
            </div>

            <div class="col-md-6 mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
                <ValidationMessage For="() => Model.StudentId" />
            </div>
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                <option value="0">— Select a course —</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.Code – @course.Title (@course.Credits cr)</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool Submitted { get; set; }

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        Submitted = true;
    }
}

